      "trust_model": {
        "actors": [
          {
            "id": "actor-tx-submitter",
            "name": "Transaction Submitter (User / EOA / Contract)",
            "description": "An external user, externally-owned account, or smart contract that constructs and submits a transaction to the Ethereum network with a specified gasLimit field. This is an untrusted actor who controls the transaction parameters including gasLimit."
          },
          {
            "id": "actor-txpool",
            "name": "Transaction Pool (Mempool)",
            "description": "The local transaction pool maintained by each execution client node. It receives incoming transactions, applies validation rules (including the EIP-7825 gas cap check), and holds valid transactions pending inclusion in a block. Each node's txpool operates independently."
          },
          {
            "id": "actor-block-builder",
            "name": "Block Builder / Proposer",
            "description": "The entity responsible for constructing a candidate block from pending transactions in the txpool. In post-PBS Ethereum, this may be a specialized block builder or the validator itself. The block builder selects transactions and assembles them into a block."
          },
          {
            "id": "actor-block-validator",
            "name": "Block Validator (Consensus Participant)",
            "description": "A node that receives a proposed block and independently validates it according to protocol rules, including verifying that every transaction in the block has gasLimit <= 16777216 (EIP-7825). Validators collectively enforce consensus by rejecting invalid blocks."
          },
          {
            "id": "actor-execution-engine",
            "name": "Execution Engine / EVM",
            "description": "The Ethereum Virtual Machine execution environment within each client that processes transactions within validated blocks. It executes smart contract code, including precompiled contracts like ModExp (0x05). It is trusted to correctly compute gas costs and state transitions."
          },
          {
            "id": "actor-modexp-caller",
            "name": "ModExp Precompile Caller (Smart Contract)",
            "description": "Any smart contract that invokes the ModExp precompiled contract at address 0x05 via CALL/STATICCALL, supplying base, exponent, and modulus parameters. This is an untrusted actor that controls all input parameters to the precompile. Common use cases include RSA signature verification, zero-knowledge proof systems, and other cryptographic operations."
          },
          {
            "id": "actor-modexp-precompile",
            "name": "ModExp Precompiled Contract (0x05)",
            "description": "The modular exponentiation precompiled contract at address 0x05. It computes base^exponent mod modulus with gas cost determined by the EIP-7883 formula: max(500, floor(multiplication_complexity * iteration_count)). It is part of the trusted EVM execution environment."
          },
          {
            "id": "actor-protocol-governance",
            "name": "Protocol Governance (EIP Process)",
            "description": "The Ethereum governance process that defines protocol constants such as the gas cap value (2^24 = 16777216) and the ModExp gas pricing formula. These constants are embedded in client implementations and are trusted as canonical once activated via a hard fork."
          }
        ],
        "trust_boundaries": [
          {
            "id": "tb-001",
            "from_actor": "actor-tx-submitter",
            "to_actor": "actor-txpool",
            "description": "A transaction submitter sends a transaction with an arbitrary gasLimit to a node's transaction pool via RPC or P2P gossip. The txpool must validate the gasLimit against the protocol cap (16777216) before admitting the transaction. This is the first line of defense against oversized transactions."
          },
          {
            "id": "tb-002",
            "from_actor": "actor-txpool",
            "to_actor": "actor-block-builder",
            "description": "The transaction pool provides validated transactions to the block builder for inclusion in a candidate block. The block builder trusts that the txpool has already filtered out transactions exceeding the gas cap. However, a malicious or buggy txpool implementation could pass through invalid transactions."
          },
          {
            "id": "tb-003",
            "from_actor": "actor-block-builder",
            "to_actor": "actor-block-validator",
            "description": "The block builder submits a candidate block containing transactions to validators. Validators must independently re-verify that every transaction in the block has gasLimit <= 16777216, providing a second enforcement layer. This defense-in-depth approach means a bypass at the txpool layer does not compromise the system."
          },
          {
            "id": "tb-004",
            "from_actor": "actor-block-validator",
            "to_actor": "actor-execution-engine",
            "description": "After a block passes validation (including the gas cap check), the execution engine processes the transactions within the block. The execution engine trusts that block-level validation has been correctly performed before it begins execution."
          },
          {
            "id": "tb-005",
            "from_actor": "actor-modexp-caller",
            "to_actor": "actor-modexp-precompile",
            "description": "An untrusted smart contract invokes the ModExp precompile with arbitrary base_length, modulus_length, exponent_length, and the corresponding data. The precompile must correctly compute gas costs using the EIP-7883 formula regardless of input values. This is the primary attack surface for gas mispricing exploits."
          },
          {
            "id": "tb-006",
            "from_actor": "actor-modexp-precompile",
            "to_actor": "actor-execution-engine",
            "description": "The ModExp precompile reports its gas consumption to the execution engine. The gas cost is deterministically computed from inputs using the EIP-7883 formula. The execution engine trusts this gas computation to be correct and deducts it from the caller's available gas."
          },
          {
            "id": "tb-007",
            "from_actor": "actor-protocol-governance",
            "to_actor": "actor-execution-engine",
            "description": "Protocol governance defines the gas cap constant (16777216), the ModExp pricing formula, and the minimum gas floor (500). All execution clients must implement these identical constants. Divergent implementations would cause consensus splits."
          },
          {
            "id": "tb-008",
            "from_actor": "actor-tx-submitter",
            "to_actor": "actor-block-validator",
            "description": "In scenarios where transactions bypass the txpool (e.g., private transaction channels, direct-to-builder submission, or compromised nodes injecting transactions), the block validator serves as the ultimate enforcement point for the gas cap. Block validation must be comprehensive and independent of txpool filtering."
          }
        ],
        "assumptions": [
          {
            "id": "asm-001",
            "text": "The gas cap constant GAS_CAP = 16777216 (2^24) is a fixed protocol constant that cannot be changed without a hard fork. All clients implement the identical value."
          },
          {
            "id": "asm-002",
            "text": "The gas cap is independent of the block gas limit. Even if the block gas limit exceeds 16777216 (which it typically does at 30-40M), no individual transaction may specify a gasLimit above the cap. Multiple transactions can collectively exceed the cap within a single block."
          },
          {
            "id": "asm-003",
            "text": "The gas cap is enforced at exactly two layers: (1) transaction pool admission and (2) block validation. These two enforcement points provide defense-in-depth. A failure at layer 1 is caught at layer 2."
          },
          {
            "id": "asm-004",
            "text": "A transaction rejected at the txpool layer never reaches block validation (INV-009). This assumes the txpool correctly implements the rejection and does not have a race condition or bypass path that allows rejected transactions to leak into block building."
          },
          {
            "id": "asm-005",
            "text": "Block validation iterates over ALL transactions in the block before acceptance (INV-005). There is no early-exit optimization that could skip checking some transactions. A single violating transaction invalidates the entire block (INV-006)."
          },
          {
            "id": "asm-006",
            "text": "The gas cap value (16777216) is the same at both the txpool validation layer and the block validation layer (INV-008). If these values diverge due to a client bug, transactions could pass one check but fail the other, leading to blocks that are built but rejected."
          },
          {
            "id": "asm-007",
            "text": "The gas cap applies uniformly to all transaction types (legacy, EIP-2930, EIP-1559, EIP-4844 blob transactions, etc.) regardless of the block gas limit set by validators (INV-010)."
          },
          {
            "id": "asm-008",
            "text": "The ModExp gas cost formula (EIP-7883) is deterministic: for identical inputs, all client implementations compute the identical gas cost. Non-determinism would cause consensus failures where some nodes accept a block and others reject it due to different gas accounting."
          },
          {
            "id": "asm-009",
            "text": "The multiplication_complexity function has a minimum output of 16 for all inputs (INV-001 of SG-001 in EIP-7883). This ensures a baseline computational cost is always charged even for small operands."
          },
          {
            "id": "asm-010",
            "text": "For inputs with max(base_length, modulus_length) <= 32, the multiplication_complexity is fixed at 16, avoiding unnecessary computation of the word-based formula for small inputs (INV-002 of SG-001 in EIP-7883)."
          },
          {
            "id": "asm-011",
            "text": "The iteration_count is always >= 1 for all non-trivial inputs (INV-001 of SG-002 in EIP-7883). The max(iteration_count, 1) clamp for large exponents ensures no zero-cost execution paths exist."
          },
          {
            "id": "asm-012",
            "text": "The large exponent multiplier has been doubled from 8 (EIP-2565) to 16 (EIP-7883) (INV-003 of SG-002). This corrects the underpricing of large-exponent operations, which was the primary vulnerability allowing resource exhaustion attacks."
          },
          {
            "id": "asm-013",
            "text": "The minimum gas floor for ModExp is 500 (raised from 200 in EIP-2565). This ensures that even trivial inputs incur a meaningful gas cost, preventing cheap abuse of the precompile. The formula is max(500, floor(complexity * iterations)) with no division by 3 (INV-002 of SG-003)."
          },
          {
            "id": "asm-014",
            "text": "The removal of the division by 3 from the gas formula (previously present in EIP-2565 as gas = max(200, floor(complexity * iterations / 3))) represents a roughly 3x increase in gas costs for most operations, which is assumed to be a net improvement in security even at the cost of higher fees for legitimate users."
          },
          {
            "id": "asm-015",
            "text": "The EIP-7883 gas cost increase does not introduce new functionality or attack surfaces; it only makes existing operations more expensive. The security argument is that overpricing is strictly safer than underpricing for consensus-critical operations."
          }
        ],
        "stride_analysis": [
          {
            "trust_boundary_id": "tb-001",
            "threat_type": "Spoofing",
            "description": "A malicious actor could impersonate a legitimate user and submit transactions with gasLimit values just below the cap (e.g., 16777216) to maximize resource consumption per transaction. While the transaction is technically valid, the intent is adversarial resource exhaustion.",
            "mitigation": "The gas cap itself limits damage. Each transaction can consume at most 16777216 gas, which is approximately half a typical block. Additional rate limiting, fee-based prioritization (EIP-1559 base fee), and txpool eviction policies provide further defense."
          },
          {
            "trust_boundary_id": "tb-001",
            "threat_type": "Tampering",
            "description": "A transaction submitter could craft a transaction with a gasLimit exceeding 16777216 to attempt to consume excessive block resources. If the txpool validation has an integer overflow, off-by-one error, or type confusion vulnerability in the comparison against the constant, the invalid transaction could be admitted.",
            "mitigation": "The check is a simple integer comparison (gasLimit > 16777216) performed at the txpool layer (SG-001). The constant 2^24 is easily representable in all numeric types. Block-level validation (SG-002) provides a second check. Both layers must be bypassed for an attack to succeed."
          },
          {
            "trust_boundary_id": "tb-001",
            "threat_type": "Denial of Service",
            "description": "An attacker could flood the txpool with high volumes of transactions at or near the gasLimit cap. While each transaction is individually valid, the aggregate volume could overwhelm txpool storage, eviction logic, and network bandwidth for transaction gossip.",
            "mitigation": "Standard txpool size limits, mempool eviction policies (lowest fee eviction), per-sender nonce sequencing, and EIP-1559 base fee adjustments limit the effectiveness of txpool flooding. The gas cap does not make this worse than the status quo; it actually bounds the maximum size of individual transactions."
          },
          {
            "trust_boundary_id": "tb-002",
            "threat_type": "Tampering",
            "description": "A compromised or buggy txpool implementation could allow transactions with gasLimit > 16777216 to pass through to the block builder. If the block builder does not independently verify the gas cap (relying solely on the txpool's filtering), it could include invalid transactions in a candidate block.",
            "mitigation": "Defense-in-depth design (INV-007): the gas cap is enforced at both txpool and block validation layers. Even if the txpool is bypassed, block validators will reject any block containing a transaction exceeding the cap. Block builders that produce invalid blocks waste their computational resources and forfeit MEV opportunities."
          },
          {
            "trust_boundary_id": "tb-003",
            "threat_type": "Tampering",
            "description": "A malicious block builder could intentionally construct a block containing a transaction with gasLimit > 16777216, hoping that some validators have a buggy implementation that skips the per-transaction gas cap check during block validation.",
            "mitigation": "Block validation must iterate over ALL transactions (INV-005) and reject the entire block if any single transaction violates the cap (INV-006). The check is straightforward (integer comparison per transaction), and multi-client diversity ensures that a bug in one client is caught by honest nodes running other clients."
          },
          {
            "trust_boundary_id": "tb-003",
            "threat_type": "Denial of Service",
            "description": "A malicious block builder could create blocks with the maximum number of transactions, each at exactly the gasLimit cap (16777216), to maximize block validation time. Validators must check every transaction in the block, and a block packed with cap-sized transactions maximizes both the iteration count and the per-transaction gas execution load.",
            "mitigation": "The block gas limit (typically 30M) naturally limits the number of transactions that can fit at the cap. At a 16777216 gas cap, only 1-2 transactions at the cap can fit in a standard block. The block gas limit thus provides an implicit bound on the aggregate validation and execution cost."
          },
          {
            "trust_boundary_id": "tb-003",
            "threat_type": "Repudiation",
            "description": "A block builder that produces an invalid block (containing transactions exceeding the gas cap) cannot repudiate this action, since the block contents are signed and publicly visible. However, in private transaction channels (e.g., Flashbots), the builder might attempt to blame the transaction submitter for the invalid gasLimit.",
            "mitigation": "Block validation is deterministic and independently verifiable by all nodes. The block builder bears responsibility for the contents of their block regardless of the transaction source. Signed blocks provide non-repudiation."
          },
          {
            "trust_boundary_id": "tb-004",
            "threat_type": "Elevation of Privilege",
            "description": "If the gas cap check passes at the block validation layer but is not correctly enforced by the execution engine (e.g., the EVM allows a transaction to consume more gas than its stated gasLimit through a re-entrancy or gas stipend bug), the transaction could effectively bypass the cap during execution.",
            "mitigation": "The gas cap applies to the transaction's declared gasLimit field, not to actual gas consumed. The EVM already enforces that a transaction cannot consume more gas than its gasLimit. The EIP-7825 cap simply adds an upper bound on what that declared gasLimit can be."
          },
          {
            "trust_boundary_id": "tb-005",
            "threat_type": "Tampering",
            "description": "A malicious smart contract could craft ModExp inputs with carefully chosen base_length, modulus_length, and exponent_length values designed to exploit edge cases in the gas cost calculation. For example, setting base_length or modulus_length to very large values while keeping actual data small, or using exponent_length > 32 to trigger the large-exponent path with minimal actual computational cost, attempting to find inputs where the gas charged is much less than actual computation time.",
            "mitigation": "EIP-7883 significantly increases gas costs across the board: the minimum floor is raised from 200 to 500, the division by 3 is removed (effective 3x increase), and the large exponent multiplier is doubled from 8 to 16. The multiplication_complexity formula ensures costs scale quadratically with operand size (2 * words^2). These changes close the gap between charged gas and actual computation time."
          },
          {
            "trust_boundary_id": "tb-005",
            "threat_type": "Denial of Service",
            "description": "An attacker could invoke the ModExp precompile with inputs that maximize computation time relative to the gas charged. Before EIP-7883, the gas formula underpriced certain operations (particularly large exponent operations), allowing an attacker to consume disproportionate CPU time per unit of gas spent. This is the primary threat that EIP-7883 is designed to address, as the underpricing becomes more dangerous if the block gas limit is increased.",
            "mitigation": "EIP-7883 directly addresses this by: (1) raising the minimum gas from 200 to 500, (2) removing the /3 divisor making all operations 3x more expensive, (3) doubling the large exponent multiplier from 8 to 16, and (4) establishing a minimum multiplication_complexity of 16. Historical analysis shows approximately 99.69% of ModExp calls will see 150-200% cost increases, with worst-case scenarios seeing up to 9105% increases."
          },
          {
            "trust_boundary_id": "tb-005",
            "threat_type": "Information Disclosure",
            "description": "The ModExp precompile processes potentially sensitive cryptographic inputs (RSA keys, ZK proof components). Execution time variations based on input values could leak information about the operands to co-located observers through timing side-channels.",
            "mitigation": "ModExp operates on public blockchain data, so input confidentiality is not a primary concern (all inputs are visible on-chain). However, clients should still aim for consistent execution times to avoid creating exploitable timing oracles. The gas pricing changes in EIP-7883 do not address timing channels."
          },
          {
            "trust_boundary_id": "tb-006",
            "threat_type": "Tampering",
            "description": "If different client implementations compute different gas costs for the same ModExp inputs (due to integer arithmetic differences, rounding behavior in floor(), or different interpretations of the ceiling function in words calculation), they would disagree on whether a transaction has sufficient gas, causing a consensus split.",
            "mitigation": "The EIP-7883 formulas use only integer arithmetic: ceil(max_length / 8) for word count, integer multiplication for complexity, and floor() for final cost. All operations are deterministic over integers. Multi-client test vectors and fuzzing should be used to verify cross-client consistency. The specification explicitly defines all branch conditions and formulas."
          },
          {
            "trust_boundary_id": "tb-006",
            "threat_type": "Elevation of Privilege",
            "description": "If the gas cost calculation has an integer overflow vulnerability (e.g., 2 * words^2 overflowing for very large max_length values, or complexity * iterations overflowing), the computed gas could wrap to a small value, allowing an attacker to execute expensive ModExp operations for minimal gas cost.",
            "mitigation": "Client implementations must use sufficiently large integer types (256-bit or arbitrary precision) for gas calculations. The inputs base_length, modulus_length, and exponent_length are bounded by the transaction's calldata size, which is in turn bounded by the block gas limit and the EIP-7825 transaction gas cap. These implicit bounds limit the maximum values that can appear in the formula."
          },
          {
            "trust_boundary_id": "tb-007",
            "threat_type": "Tampering",
            "description": "If the EIP activation occurs inconsistently across the network (some nodes activate at a different block/fork than others), transactions and blocks could be valid under one pricing regime but invalid under another, causing a chain split.",
            "mitigation": "Both EIP-7825 and EIP-7883 are activated via a coordinated hard fork (Fusaka). All clients must activate the new rules at the same block height. The hard fork coordination process includes extensive testnet validation and client readiness verification before mainnet activation."
          },
          {
            "trust_boundary_id": "tb-007",
            "threat_type": "Repudiation",
            "description": "After the hard fork activates EIP-7883, smart contracts that previously relied on specific ModExp gas costs may fail or behave differently. Contract deployers could claim they were not adequately warned about the pricing change.",
            "mitigation": "The EIP process includes public discussion, testnet deployment, and community review periods. The backward-incompatible nature of the change is explicitly documented. Historical analysis shows the impact on existing contracts (99.69% of calls see 150-200% increases). Contracts should not hard-code gas amounts for precompile calls."
          },
          {
            "trust_boundary_id": "tb-008",
            "threat_type": "Tampering",
            "description": "In private transaction submission channels (e.g., Flashbots Protect, MEV Boost relays), transactions may bypass the public txpool entirely and be sent directly to a block builder. A malicious relay or builder could inject transactions with gasLimit > 16777216 that never went through txpool validation.",
            "mitigation": "Block-level validation (SG-002 of EIP-7825) serves as the ultimate enforcement point regardless of how transactions enter the block. Every validator independently checks every transaction in every block. The two-layer enforcement (INV-007) ensures that bypassing the txpool layer does not compromise the system."
          },
          {
            "trust_boundary_id": "tb-008",
            "threat_type": "Spoofing",
            "description": "In MEV-Boost or PBS architectures, the block builder is a separate entity from the proposer. A malicious builder could construct a block with gas-cap-violating transactions and submit it through a relay, hoping the proposer blindly signs without full validation.",
            "mitigation": "Proposers (validators) must validate the block before signing. The MEV-Boost protocol requires that the relay verifies block validity. Even if the relay is compromised, the proposer's own validation and the network's block validation by attesting validators will reject invalid blocks."
          }
        ]
      },
      "_source_file": "outputs/01d_PARTIAL_W0B1_1770284080.json"
    }
  ],
  "total_items": 1
}

